 11→class ThreadLocalStressTest : TestBase() {
 12→
 13→    private val threadLocal = ThreadLocal<String>()
 14→
 15→    // See the comment in doStress for the machinery
 16→    @Test
 17→    fun testStress() = runTest {
 18→        repeat (100 * stressTestMultiplierSqrt) {
 19→            withContext(Dispatchers.Default) {
 20→                repeat(100) {
 21→                    launch {
 22→                        doStress(null)
 23→                    }
 24→                }
 25→            }
 26→        }
 27→    }
 28→
 29→    @Test
 30→    fun testStressWithOuterValue() = runTest {
 31→        repeat (100 * stressTestMultiplierSqrt) {
 32→            withContext(Dispatchers.Default + threadLocal.asContextElement("bar")) {
 33→                repeat(100) {
 34→                    launch {
 35→                        doStress("bar")
 36→                    }
 37→                }
 38→            }
 39→        }
 40→    }
 41→
 42→    private suspend fun doStress(expectedValue: String?) {
 43→        assertEquals(expectedValue, threadLocal.get())
 44→        try {
 45→            /*
 46→             * Here we are using very specific code-path to trigger the execution we want to.
 47→             * The bug, in general, has a larger impact, but this particular code pinpoints it:
 48→             *
 49→             * 1) We use _undispatched_ withContext with thread element
 50→             * 2) We cancel the coroutine
 51→             * 3) We use 'suspendCancellableCoroutineReusable' that does _postponed_ cancellation check
 52→             *    which makes the reproduction of this race pretty reliable.
 53→             *
 54→             * Now the following code path is likely to be triggered:
 55→             *
 56→             * T1 from within 'withContinuationContext' method:
 57→             * Finds 'oldValue', finds undispatched completion, invokes its 'block' argument.
 58→             * 'block' is this coroutine, it goes to 'trySuspend', checks for postponed cancellation and *dispatches* it.
 59→             * The execution stops _right_ before 'undispatchedCompletion.clearThreadContext()'.
 60→             *
 61→             * T2 now executes the dispatched cancellation and concurrently mutates the state of the undispatched completion.
 62→             * All bets are off, now both threads can leave the thread locals state inconsistent.
 63→             */
 64→            withContext(threadLocal.asContextElement("foo")) {
 65→                yield()
 66→                cancel()
 67→                suspendCancellableCoroutineReusable<Unit> { }
 68→            }
 69→        } finally {
 70→            assertEquals(expectedValue, threadLocal.get())
 71→        }
 72→    }
 73→
 74→    /*
 75→     * Another set of tests for undispatcheable continuations that do not require stress test multiplier.
 76→     * Also note that `uncaughtExceptionHandler` is used as the only available mechanism to propagate error from
 77→     * `resumeWith`
 78→     */
 79→
 80→    @Test
 81→    fun testNonDispatcheableLeak() {
 82→        repeat(100) {
 83→            doTestWithPreparation(
 84→                ::doTest,
 85→                { threadLocal.set(null) }) { threadLocal.get() == null }
 86→            assertNull(threadLocal.get())
 87→        }
 88→    }
 89→
 90→    @Test
 91→    fun testNonDispatcheableLeakWithInitial() {
 92→        repeat(100) {
 93→            doTestWithPreparation(::doTest, { threadLocal.set("initial") }) { threadLocal.get() == "initial" }
 94→            assertEquals("initial", threadLocal.get())
 95→        }
 96→    }
 97→
 98→    @Test
 99→    fun testNonDispatcheableLeakWithContextSwitch() {
100→        repeat(100) {
101→            doTestWithPreparation(
102→                ::doTestWithContextSwitch,
103→                { threadLocal.set(null) }) { threadLocal.get() == null }
104→            assertNull(threadLocal.get())
105→        }
106→    }
107→
108→    @Test
109→    fun testNonDispatcheableLeakWithInitialWithContextSwitch() {
110→        repeat(100) {
111→            doTestWithPreparation(
112→                ::doTestWithContextSwitch,
113→                { threadLocal.set("initial") }) { true /* can randomly wake up on the non-main thread */ }
114→            // Here we are always on the main thread
115→            assertEquals("initial", threadLocal.get())
116→        }
117→    }
118→
119→    private fun doTestWithPreparation(testBody: suspend () -> Unit, setup: () -> Unit, isValid: () -> Boolean) {
120→        setup()
121→        val latch = CountDownLatch(1)
122→        testBody.startCoroutineUninterceptedOrReturn(Continuation(EmptyCoroutineContext) {
123→            if (!isValid()) {
124→                Thread.currentThread().uncaughtExceptionHandler.uncaughtException(
125→                    Thread.currentThread(),
126→                    IllegalStateException("Unexpected error: thread local was not cleaned")
127→                )
128→            }
129→            latch.countDown()
130→        })
131→        latch.await()
132→    }
133→
134→    private suspend fun doTest() {
135→        withContext(threadLocal.asContextElement("foo")) {
136→            try {
137→                coroutineScope {
138→                    val semaphore = Semaphore(1, 1)
139→                    cancel()
140→                    semaphore.acquire()
141→                }
142→            } catch (e: CancellationException) {
143→                // Ignore cancellation
144→            }
145→        }
146→    }
147→
148→    private suspend fun doTestWithContextSwitch() {
149→        withContext(threadLocal.asContextElement("foo")) {
150→            try {
151→                coroutineScope {
152→                    val semaphore = Semaphore(1, 1)
153→                    GlobalScope.launch { }.join()
154→                    cancel()
155→                    semaphore.acquire()
156→                }
157→            } catch (e: CancellationException) {
158→                // Ignore cancellation
159→            }
160→        }
161→    }
162→}
